CREATE INDEX "idx_usage_event_processed_org_user" ON "usage_event" USING btree ("processed_at" DESC NULLS LAST,"org_id","user_id") WHERE "usage_event"."status" = 'processed' AND "usage_event"."processed_at" IS NOT NULL;